{
  "mode": "method",
  "tests": [
    {
      "name": "test_save_for_later_no_submission",
      "input": {
        "action": "save_for_later",
        "review_score": 5,
        "submission_id": "12345"
      },
      "output": {
        "submitted": false,
        "score": 5
      },
      "notes": "Validates that clicking 'Save for later' does not submit the score."
    },
    {
      "name": "test_save_for_later_with_empty_score",
      "input": {
        "action": "save_for_later",
        "review_score": null,
        "submission_id": "12346"
      },
      "output": {
        "submitted": false,
        "score": null
      },
      "notes": "Checks behavior when no score is provided."
    },
    {
      "name": "test_save_for_later_multiple_clicks",
      "input": {
        "action": "save_for_later",
        "review_score": 4,
        "submission_id": "12347"
      },
      "output": {
        "submitted": false,
        "score": 4
      },
      "notes": "Ensures multiple clicks on 'Save for later' do not submit the score."
    },
    {
      "name": "test_save_for_later_with_invalid_submission_id",
      "input": {
        "action": "save_for_later",
        "review_score": 3,
        "submission_id": ""
      },
      "output": {
        "submitted": false,
        "score": 3
      },
      "notes": "Tests behavior with an invalid submission ID."
    },
    {
      "name": "test_save_for_later_with_negative_score",
      "input": {
        "action": "save_for_later",
        "review_score": -1,
        "submission_id": "12348"
      },
      "output": {
        "submitted": false,
        "score": -1
      },
      "notes": "Validates that a negative score does not get submitted."
    },
    {
      "name": "test_save_for_later_with_high_score",
      "input": {
        "action": "save_for_later",
        "review_score": 10,
        "submission_id": "12349"
      },
      "output": {
        "submitted": false,
        "score": 10
      },
      "notes": "Checks that a high score is not submitted."
    },
    {
      "name": "test_save_for_later_with_non_numeric_score",
      "input": {
        "action": "save_for_later",
        "review_score": "five",
        "submission_id": "12350"
      },
      "output": {
        "submitted": false,
        "score": "five"
      },
      "notes": "Ensures non-numeric scores are handled correctly."
    },
    {
      "name": "test_save_for_later_with_valid_score_and_submission",
      "input": {
        "action": "save_for_later",
        "review_score": 7,
        "submission_id": "12351"
      },
      "output": {
        "submitted": false,
        "score": 7
      },
      "notes": "Validates that a valid score is not submitted when 'Save for later' is clicked."
    }
  ],
  "assumptions": "The system must not submit scores when 'Save for later' is clicked.",
  "notes": "All tests focus on the behavior of the 'Save for later' button."
}
